import express, { Request, Response } from "express";
import path from "path";
import dotenv from "dotenv";
import { GoogleGenAI } from "@google/genai";
import { createServer as createViteServer } from "vite";

// Load environment variables
dotenv.config();

// Initialize Gemini API client on the server
// Note: We use process.env.GEMINI_API_KEY server-side, and set User-Agent for telemetry
const ai = new GoogleGenAI({
  apiKey: process.env.GEMINI_API_KEY,
  httpOptions: {
    headers: {
      'User-Agent': 'aistudio-build',
    }
  }
});

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Body parsers
  app.use(express.json());

  // API Route: Dynamic Clues (Reverse Geocode -> REST Countries -> Gemini Dynamic Translation)
  app.post("/api/clues", async (req: Request, res: Response): Promise<void> => {
    try {
      const { lat, lng, clueIndex } = req.body;

      if (typeof lat !== 'number' || typeof lng !== 'number') {
        res.status(400).json({ error: "Parâmetros lat e lng inválidos." });
        return;
      }

      // Step 1: Reverse Geocode via OpenStreetMap Nominatim
      // Nominatim requires a descriptive User-Agent header
      const nominatimUrl = `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=5&addressdetails=1`;
      
      let countryCode = "";
      let countryNameFromOSM = "";
      let addressName = "";

      try {
        const osmRes = await fetch(nominatimUrl, {
          headers: {
            "User-Agent": "GeoGuessrMapillaryClone/1.0 (tl.andrade.2024@aluno.unila.edu.br)"
          }
        });
        if (osmRes.ok) {
          const osmData = await osmRes.json();
          countryCode = (osmData.address?.country_code || "").toLowerCase();
          countryNameFromOSM = osmData.address?.country || "";
          addressName = osmData.display_name || "";
        }
      } catch (osmErr) {
        console.error("Erro ao consultar Nominatim:", osmErr);
      }

      // Fallback default if Nominatim fails or returns nothing
      if (!countryCode) {
        // Fallback simple heuristics based on coordinates if offline
        countryCode = "br"; // fallback default
      }

      // Step 2: Query REST Countries API
      const countriesUrl = `https://restcountries.com/v3.1/alpha/${countryCode}?fields=name,continents,subregion,car,idd,currencies,tld,languages`;
      let countryFacts: any = null;

      try {
        const rcRes = await fetch(countriesUrl);
        if (rcRes.ok) {
          const rcData = await rcRes.json();
          countryFacts = rcData;
        }
      } catch (rcErr) {
        console.error("Erro ao consultar REST Countries:", rcErr);
      }

      if (!countryFacts) {
        res.status(500).json({ error: "Não foi possível obter dados geográficos do país." });
        return;
      }

      // Extract specific facts
      const continent = (countryFacts.continents || []).join(", ") || "Desconhecido";
      const subregion = countryFacts.subregion || "Desconhecido";
      const driveSide = countryFacts.car?.side === "left" ? "lado esquerdo (mão inglesa)" : "lado direito (padrão)";
      
      const callingCodeRoot = countryFacts.idd?.root || "";
      const callingCodeSuffix = (countryFacts.idd?.suffixes || [])[0] || "";
      const callingCode = callingCodeRoot + callingCodeSuffix || "Desconhecido";

      const currencyKeys = Object.keys(countryFacts.currencies || {});
      const currencyObj = currencyKeys.length > 0 ? countryFacts.currencies[currencyKeys[0]] : null;
      const currencyName = currencyObj ? `${currencyObj.name} (${currencyObj.symbol || ''})` : "Desconhecida";
      
      const tld = (countryFacts.tld || []).join(", ") || "Desconhecido";
      const languages = Object.values(countryFacts.languages || {}).join(", ") || "Desconhecido";
      const countryOfficialName = countryFacts.name?.official || countryFacts.name?.common || "este local";

      // Prepare Gemini prompts for dynamic, non-templated text generation
      let factPrompt = "";
      let categoryName = "";

      switch (clueIndex) {
        case 0: // Geografia Geral
          categoryName = "Geografia Geral";
          factPrompt = `Continente: ${continent}, Sub-região: ${subregion}.`;
          break;
        case 1: // Tráfego e Telecomunicação
          categoryName = "Tráfego e Telecomunicação";
          factPrompt = `Os carros trafegam pelo ${driveSide} da pista. O código de discagem direta internacional (DDI) começa com ${callingCode}.`;
          break;
        case 2: // Economia e Web
          categoryName = "Economia e Web";
          factPrompt = `A moeda oficial é o ${currencyName}. O domínio nacional de internet termina em ${tld}.`;
          break;
        case 3: // Cultura e Linguística
          categoryName = "Cultura e Linguística";
          factPrompt = `O principal idioma oficial ou nativo falado e escrito nesta região é: ${languages}.`;
          break;
        default:
          res.status(400).json({ error: "Código de dica inválido." });
          return;
      }

      // Check if Gemini API Key is available
      if (!process.env.GEMINI_API_KEY || process.env.GEMINI_API_KEY === "MY_GEMINI_API_KEY") {
        // Fallback standard clues without Gemini to prevent crashes on startup/empty keys
        let fallbackText = "";
        if (clueIndex === 0) fallbackText = `Este local está situado no continente ${continent} (Sub-região: ${subregion}).`;
        if (clueIndex === 1) fallbackText = `Os carros trafegam pelo ${driveSide} da pista. O DDI telefônico começa com ${callingCode}.`;
        if (clueIndex === 2) fallbackText = `A moeda oficial é o ${currencyName}. O domínio nacional de internet termina em ${tld}.`;
        if (clueIndex === 3) fallbackText = `Os idiomas oficiais ou nativos falados nesta localidade incluem: ${languages}.`;
        
        res.json({
          clueIndex,
          category: categoryName,
          text: fallbackText + " (Nota: Ative sua chave GEMINI_API_KEY para descrições narrativas dinâmicas)",
          countryCode
        });
        return;
      }

      // Generate completely dynamic, non-templated hint in Portuguese using Gemini
      // Extreme instruction: NEVER REVEAL OR MENTION THE COUNTRY NAME OR MAJOR CITIES
      const systemInstruction = 
        `Você é o mestre de dicas dinâmicas de um jogo clone de GeoGuessr. 
        Sua tarefa é ler alguns dados brutos sobre um país e escrever uma única dica curta (1 ou 2 frases no máximo) em português do Brasil de maneira natural, narrativa e instigante.
        As dicas devem ser dinâmicas, nada de frases prontas ou molde de frases (escreva como um humano contaria curiosidades).
        
        REQUISITO CRÍTICO DE SEGURANÇA:
        Você está estritamente PROIBIDO de escrever o nome do país (${countryOfficialName}, ${countryNameFromOSM}), de sua capital ou de qualquer cidade do país no texto.
        Use termos neutros como "esta nação", "este território", "esta parte do mundo", "por aqui", ou simplesmente descreva a infraestrutura.
        Nunca use a estrutura "[País] é..." ou revele o nome direto. Se violar esta regra, o jogo perde o sentido!`;

      const prompt = `Escreva uma dica narrativa de nível mestre para a categoria "${categoryName}" baseando-se nestas informações:
      ${factPrompt}`;

      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: prompt,
        config: {
          systemInstruction,
          temperature: 0.8,
        }
      });

      const generatedClue = response.text?.trim() || "";

      res.json({
        clueIndex,
        category: categoryName,
        text: generatedClue,
        countryCode
      });

    } catch (error: any) {
      console.error("Erro ao gerar pistas:", error);
      res.status(500).json({ error: error?.message || "Erro desconhecido ao processar dicas." });
    }
  });

  // Serve static assets in production, otherwise use Vite middleware in development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req: Request, res: Response) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[Server] GeoGuessr Mapillary rodando na porta ${PORT}`);
  });
}

startServer();
